class RabbitMQManager:
    def __init__(self, base_url: str, username: str, password: str, verify_tls: bool = True, timeout: int = 15):
        self.base_url = base_url.rstrip("/")
        self.session = requests.Session()
        self.session.auth = (username, password)
        self.session.headers.update({"Content-Type": "application/json"})
        self.session.verify = verify_tls
        self.timeout = timeout

    def _request(self, method: str, path: str, expected=(200, 201, 204), json_body: Optional[Dict[str, Any]] = None):
        url = f"{self.base_url}{path}"
        response = self.session.request(method, url, json=json_body, timeout=self.timeout)
        if response.status_code not in expected:
            body = response.text.strip()
            raise RuntimeError(f"{method} {url} failed: {response.status_code} {body}")
