def load_config(path: str) -> Dict[str, Any]:
    with open(path, "r", encoding="utf-8") as f:
        return json.load(f)


def parse_config(data: Dict[str, Any]):
    vhosts = []
    users = []

    for item in data.get("vhosts", []):
        vhosts.append(
            VHostConfig(
                name=item["name"],
                tracing=item.get("tracing", False),
                description=item.get("description", ""),
                tags=item.get("tags", []),
            )
        )

    for item in data.get("users", []):
        permissions = [
            Permission(
                user=p.get("user", item["name"]),
                configure=p.get("configure", ".*"),
                write=p.get("write", ".*"),
                read=p.get("read", ".*"),
            )
            for p in item.get("permissions", [])
        ]
        topic_permissions = [
            TopicPermission(
                user=tp.get("user", item["name"]),
                exchange=tp["exchange"],
                write=tp.get("write", ".*"),
                read=tp.get("read", ".*"),
            )
            for tp in item.get("topic_permissions", [])
        ]
        users.append(
            UserConfig(
                name=item["name"],
                password=item.get("password"),
                tags=item.get("tags", ""),
                permissions=permissions,
                topic_permissions=topic_permissions,
            )
        )

    return vhosts, users


