def apply_configuration(manager: RabbitMQManager, config: Dict[str, Any]):
    vhosts, users = parse_config(config)

    for vhost in vhosts:
        print(f"Creating vhost: {vhost.name}")
        manager.create_vhost(vhost)

    for user in users:
        print(f"Creating user: {user.name}")
        manager.create_user(user)

    for user_item in config.get("users", []):
        username = user_item["name"]

        for perm in user_item.get("permissions", []):
            permission = Permission(
                user=perm.get("user", username),
                configure=perm.get("configure", ".*"),
                write=perm.get("write", ".*"),
                read=perm.get("read", ".*"),
            )
            vhost = perm["vhost"]
            print(f"Setting permissions for user={permission.user} on vhost={vhost}")
            manager.set_permissions(vhost, permission)

        for tp in user_item.get("topic_permissions", []):
            topic_permission = TopicPermission(
                user=tp.get("user", username),
                exchange=tp["exchange"],
                write=tp.get("write", ".*"),
                read=tp.get("read", ".*"),
            )
            vhost = tp["vhost"]
            print(f"Setting topic permissions for user={topic_permission.user} on vhost={vhost}, exchange={topic_permission.exchange}")
            manager.set_topic_permissions(vhost, topic_permission)


def env_default(name: str, default: Optional[str] = None) -> Optional[str]:
    return os.environ.get(name, default)


